import { GoogleGenAI } from "@google/genai";
import { MoodLevel } from "../types";

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getCompanionInsight = async (mood: MoodLevel, recentLogs: any[]): Promise<string> => {
  try {
    if (!process.env.API_KEY) {
      return "Gemini API Key missing. Unable to generate insight.";
    }

    const moodPrompts: Record<MoodLevel, string> = {
      [MoodLevel.ROCKET]: "The user is in a 'Rocket' state (Mania/Impulsive). Suggest slowing down gently. Do not preach.",
      [MoodLevel.FERRIS_WHEEL]: "The user is in a 'Ferris Wheel' state (Hypomania/Creative). Acknowledge the energy but remind them to eat/sleep.",
      [MoodLevel.STEADY]: "The user is 'Steady'. Just a calm, supportive nod.",
      [MoodLevel.HOLDING_BREATH]: "The user is 'Holding Breath' (Mild depression/Functioning but hard). Validate their effort.",
      [MoodLevel.DEEP_SEA]: "The user is in 'Deep Sea' (Severe depression). Offer gentle presence. No 'cheer up'.",
      [MoodLevel.ABYSS]: "The user is in the 'Abyss' (Crisis). Be extremely gentle, remind them they are safe here.",
    };

    const prompt = `
      You are a companion for someone with Bipolar Disorder. The app philosophy is "Allow fluctuations, record precisely."
      The user just logged their state as: ${mood}.
      Context: ${moodPrompts[mood]}

      Task: Write a SINGLE sentence (max 25 words).
      Tone: Non-judgmental, low pressure, calm.
      Do not use words like "hope", "better", "cure", "happy".
      Just objective observation or gentle company.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text?.trim() || "Recorded.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Recorded.";
  }
};

