         <h3 className="text-xs font-bold text-stone-400 tracking-widest uppercase">多维波动模式</h3>
         <div className="flex gap-3 text-[10px]">
             <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-stone-500"></div><span className="text-stone-400">情绪</span></div>
             <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-sm bg-indigo-100"></div><span className="text-stone-400">睡眠</span></div>
             <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-rose-400"></div><span className="text-stone-400">经期</span></div>
         </div>
      </div>

      <div className="flex-1">
        <ResponsiveContainer width="100%" height="100%">
          <ComposedChart data={MOCK_DATA}>
            <XAxis 
              dataKey="date" 
              axisLine={false} 
              tickLine={false} 
              tick={{fill: '#a8a29e', fontSize: 10}}
              dy={10}
            />
            {/* Left Axis: Mood (-3 to 3) */}
            <YAxis 
              yAxisId="mood"
              hide 
              domain={[-3, 4]} // Extra space at top for markers
            />
            {/* Right Axis: Sleep (0 to 14) */}
            <YAxis 
              yAxisId="sleep" 
              orientation="right" 
              hide 
              domain={[0, 14]} 
            />

            <ReferenceLine yAxisId="mood" y={0} stroke="#e7e5e4" strokeDasharray="3 3" />

            <Tooltip 
              contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
              labelStyle={{ color: '#78716c', fontWeight: 'bold' }}
              itemStyle={{ fontSize: '12px' }}
              formatter={(value: any, name: string) => {
                 if (name === 'value') return [value, 'Mood'];
                 if (name === 'sleep') return [value + 'h', 'Sleep'];
                 if (name === 'menstruationValue') return [null, '']; // Hide scatter value
                 return [value, name];
              }}
            />

            {/* Sleep Bars (Background-like) */}
            <Bar yAxisId="sleep" dataKey="sleep" barSize={16} radius={[4, 4, 0, 0]}>
               {MOCK_DATA.map((entry, index) => (
                 <Cell key={`cell-${index}`} fill="#e0e7ff" fillOpacity={0.6} />
               ))}
            </Bar>

            {/* Menstruation Markers (Top of chart) */}
            <Scatter yAxisId="mood" dataKey={(entry) => entry.menstruation ? 3.5 : null} fill="#fb7185" shape="circle" />

            {/* Mood Line */}
            <Line 
              yAxisId="mood"
              type="monotone" 
              dataKey="value" 
              stroke="#57534e" 
              strokeWidth={3} 
              dot={{ r: 4, fill: '#fff', stroke: '#57534e', strokeWidth: 2 }}
              activeDot={{ r: 6, strokeWidth: 0, fill: '#57534e' }}
            />
          </ComposedChart>
        </ResponsiveContainer>
      </div>

      <div className="text-center mt-4">
        <p className="text-[10px] text-stone-400">
          关联洞察：经期（Wed-Fri）期间伴随睡眠质量下降及情绪低落。
        </p>
      </div>
    </div>
  );
};

export default PatternChart;

import React, { useState, useEffect } from 'react';
import { HashRouter } from 'react-router-dom';
import { BookOpen, Settings, BarChart2 } from 'lucide-react';

import MoodSelector from './components/MoodSelector';
import MedicationButton from './components/MedicationButton';
import SafetyModal from './components/SafetyModal';
import PatternChart from './components/PatternChart';
import PhysiologicalSection from './components/PhysiologicalSection';
import { MoodLevel } from './types';
import { TAGS_POOL, MOOD_CONFIGS } from './constants';
import { getCompanionInsight } from './services/geminiService';

const App: React.FC = () => {
  const [selectedMood, setSelectedMood] = useState<MoodLevel | null>(null);
  const [medicationTaken, setMedicationTaken] = useState(false);
  const [selectedTags, setSelectedTags] = useState<string[]>([]);
  const [sleepHours, setSleepHours] = useState<number>(7.0);
  const [isMenstruating, setIsMenstruating] = useState<boolean>(false);

  const [safetyOpen, setSafetyOpen] = useState(false);
  const [companionText, setCompanionText] = useState<string>("");
  const [loadingInsight, setLoadingInsight] = useState(false);

  // Safety trigger
  useEffect(() => {
    if (selectedMood === MoodLevel.ABYSS) {
      setSafetyOpen(true);
    }
  }, [selectedMood]);

  // Insight generator
  useEffect(() => {
    let isMounted = true;
    if (selectedMood) {
      setLoadingInsight(true);
      getCompanionInsight(selectedMood, [])
        .then(text => {
          if(isMounted) {
            setCompanionText(text);
            setLoadingInsight(false);
          }
        });
    }
    return () => { isMounted = false; };
  }, [selectedMood]);

  const toggleTag = (tag: string) => {
    if (selectedTags.includes(tag)) {
      setSelectedTags(selectedTags.filter(t => t !== tag));
    } else {
      setSelectedTags([...selectedTags, tag]);
    }
  };

  const handleMoodSelect = (mood: MoodLevel) => {
    setSelectedMood(mood);
  };

  return (
    <HashRouter>
      <div className="min-h-screen bg-stone-50 pb-20 max-w-lg mx-auto shadow-2xl overflow-hidden relative">
        <header className="px-6 py-8 flex justify-between items-center">
          <div>
            <h1 className="text-2xl font-bold text-stone-800 tracking-tight">Fluctuations</h1>
            <p className="text-xs text-stone-400 mt-1">允许波动，精准记录</p>
          </div>
          <button className="text-stone-400 hover:text-stone-600 transition-colors">
            <Settings size={20} />
          </button>
        </header>

        <main className="px-6 space-y-10">

          {/* Section 1: Medication (Simplest Interaction) */}
          <section>
            <MedicationButton 
              taken={medicationTaken} 
              onToggle={setMedicationTaken} 
            />
          </section>

          {/* Section 2: Physiological (Sleep & Cycle) */}
          <section>
            <PhysiologicalSection 
              sleepHours={sleepHours}
              onSleepChange={setSleepHours}
              isMenstruating={isMenstruating}
              onMenstruationChange={setIsMenstruating}
            />
          </section>

          {/* Section 3: Mood Metaphors */}
          <section>
             <div className="flex justify-between items-end mb-4">
                <h2 className="text-sm font-bold text-stone-400 tracking-wide uppercase">当前高度</h2>
                {selectedMood && (
                   <span className={`text-xs px-2 py-1 rounded-lg bg-stone-100 text-stone-500 animate-pulse`}>
                      {loadingInsight ? "..." : companionText}
                   </span>
                )}
             </div>
            <MoodSelector 
              selectedMood={selectedMood} 
              onSelect={handleMoodSelect} 
            />
          </section>

          {/* Section 4: Tags */}
          <section>
             <h2 className="text-sm font-bold text-stone-400 tracking-wide uppercase mb-4">关键感受</h2>
             <div className="flex flex-wrap gap-2">
               {TAGS_POOL.map(tag => (
                 <button
                   key={tag}
                   onClick={() => toggleTag(tag)}
                   className={`
                     px-4 py-2 rounded-xl text-xs font-medium transition-all
                     ${selectedTags.includes(tag)
                       ? 'bg-stone-800 text-stone-50 shadow-sm'
                       : 'bg-white text-stone-500 border border-stone-100 hover:border-stone-300'
                     }
                   `}
                 >
                   {tag}
                 </button>
               ))}
             </div>
          </section>

          {/* Section 5: Insight/Chart */}
          <section>
             <PatternChart />
          </section>

          <div className="h-10"></div>
        </main>

        {/* Floating Action / Navigation */}
        <nav className="fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-md border-t border-stone-100 max-w-lg mx-auto z-40">
          <div className="flex justify-around py-4">
            <button className="flex flex-col items-center text-stone-800 gap-1">
              <BookOpen size={20} />
              <span className="text-[10px] font-medium">日记</span>
            </button>
            <button className="flex flex-col items-center text-stone-400 hover:text-stone-600 gap-1 transition-colors">
              <BarChart2 size={20} />
              <span className="text-[10px] font-medium">洞察</span>
            </button>
          </div>
        </nav>

        {/* Safety Modal */}
        <SafetyModal 
          isOpen={safetyOpen} 
          onClose={() => setSafetyOpen(false)} 
        />

      </div>
    </HashRouter>
  );
};

export default App;
